def build(src,outp):
    raw=Path(src).read_text(encoding="utf-8",errors="strict")
    out=minify(inject(raw))
    if len(out.encode())>LIMIT: die(f"generated source too large: {len(out.encode())}>{LIMIT}")
    Path(outp).write_text(out,encoding="utf-8",newline="")
    return out

